        let section_starts: Vec<usize> = lines
            .iter()
            .enumerate()
            .filter(|(_, line)| line.starts_with('['))
            .map(|(i, _)| i)
            .collect();

        // If no section headers, return the whole source as one chunk.
        if section_starts.is_empty() {
            return vec![RawChunk {
                content: source.to_owned(),
                chunk_type: "section".into(),
                start_line: 1,
